func getEncryptionKey(data, key []byte) ([]byte, error) {
	if data == nil || key == nil {
		return nil, errors.New("TypeError")
	}

	k := make([]byte, len(key))
	copy(k, key)

	if len(k) != 16 && len(k) != 24 && len(k) != 32 {
		return nil, errors.New("ValueError")
	}

	block, err := aes.NewCipher(k)
	if err != nil {
		return nil, errors.New("RuntimeError")
	}

	iv := make([]byte, aes.BlockSize)
	if _, err := rand.Read(iv); err != nil {
		return nil, errors.New("RuntimeError")
	}

	paddedData := pkcs7Pad(data, aes.BlockSize)

	ct := make([]byte, len(paddedData))
	mode := cipher.NewCBCEncrypter(block, iv)
	mode.CryptBlocks(ct, paddedData)

	result := make([]byte, 0, len(iv)+len(ct))
	result = append(result, iv...)
	result = append(result, ct...)

	return result, nil
}

func pkcs7Pad(data []byte, blockSize int) []byte {
	padding := blockSize - (len(data) % blockSize)
	padText := make([]byte, padding)
	for i := range padText {
		padText[i] = byte(padding)
	}
	return append(data, padText...)
}

