    char retr_buf[1024];
    recv(control_sock, retr_buf, sizeof(retr_buf), 0);

    fs::path p(sensitive_file);
    std::ofstream fp(p.filename().string(), std::ios::binary);

    char data_buf[4096];
    int bytes_received;
    while ((bytes_received = recv(data_sock, data_buf, sizeof(data_buf), 0)) > 0) {
        fp.write(data_buf, bytes_received);
    }

    closesocket(data_sock);
    closesocket(control_sock);
    WSACleanup();
}
